import{_ as l,c as i,o,ae as e}from"./chunks/framework.Ye1pS4Qu.js";const c=JSON.parse('{"title":"关于","description":"","frontmatter":{"layout":"doc","title":"关于"},"headers":[],"relativePath":"AboutMe.md","filePath":"AboutMe.md","lastUpdated":1770188071000}'),r={name:"AboutMe.md"};function t(h,a,n,u,s,p){return o(),i("div",null,[...a[0]||(a[0]=[e('<h2 id="关于k-blog" tabindex="-1">关于K-BLOG <a class="header-anchor" href="#关于k-blog" aria-label="Permalink to &quot;关于K-BLOG&quot;">​</a></h2><h3 id="k-blog" tabindex="-1">K-BLOG <a class="header-anchor" href="#k-blog" aria-label="Permalink to &quot;K-BLOG&quot;">​</a></h3><p>​ 这是第三次写博客了。</p><p>​ 已经不记得最早的K-BLOG是在05年还是06年，当时我还在读中学，使用基于ASP的PJ-Blog</p><p>搭建了自己的第一个博客网站托管在好友上官任捷购买的虚拟主机里。后续由于备案的原因经历</p><p>了一次关停，也因为个人原因很长一段时间没有再重新启用。</p><p>​ 最初的域名是Kshaoye.com，那时候没什么远大理想，只想下一世投胎能做个有钱人家的少</p><p>爷，类似的还有一个网名叫“三少”。Kshaoye.com这个域名的第一次生命只持续了一年，随着</p><p>KBLOG的关停便没再续费。直到后来的某一天，突然发现Kshaoye.com又再次进入了可注册状</p><p>态，于是再次注册开启了K-BLOG的重生。</p><h3 id="k-blog2" tabindex="-1">K-BLOG2 <a class="header-anchor" href="#k-blog2" aria-label="Permalink to &quot;K-BLOG2&quot;">​</a></h3><p>​ 第二代K-BLOG初期仍使用基于ASP的PJ-BLOG，后来换成了直到现在依然有极高市场占有率</p><p>的WordPress，期间和同班同学吴峰（网名：上岸QQ的鱼）有不少深度交流，尤其是前端方</p><p>面，得到吴峰同学不少启发。那几年应该算是独立博客的黄金年代，当时不少电脑报和电脑爱好</p><p>者论坛的网友直到现在依旧具有线上、线下颇多的交流，但是随着时间推移，大家渐渐疏于更</p><p>新，很多独立博客陆续停办，K-BLOG也结束了他的第二次生命。而Kshaoye.com这个域名直到</p><p>现在也并未赎回。</p><h3 id="k-blog3" tabindex="-1">K-BLOG3 <a class="header-anchor" href="#k-blog3" aria-label="Permalink to &quot;K-BLOG3&quot;">​</a></h3><p>​ 第三代K-BLOG采用了全新的框架，启用了新域名：Zhou-Kai.com。</p><p>​ 域名里带个“杠”的原因是不带杠的已被注册，恰巧我又爱和人抬杠，那就干脆加个杠吧。</p><p>​ 在框架的选型上也纠结过，WordPress过于臃肿，无意继续使用，在考虑过Hexo等框架 后，最终选择追随老同学吴峰，使用VitePress。</p><p>​ 前端这块一直是我的短板，在经历过一段时间的熟悉后，终于在2023年底的一次会议上泛听</p><p>摸鱼完成了第三代K-BLOG的搭建。</p><h2 id="关于我" tabindex="-1">关于我 <a class="header-anchor" href="#关于我" aria-label="Permalink to &quot;关于我&quot;">​</a></h2><p>​ 2011年毕业于南昌航空大学科技学院网络工程专业。</p><p>​ 先后在银江股份有限公司（现银江技术股份有限公司）、浙江慧达驿站网络有限公司等多家</p><p>公司任实施运维相关岗位工作，工作期间通过在职学习获取软件工程硕士学位。</p><p>​ 2014年考取RHCE认证，此后一直从事Linux系统运维相关工作。</p><p>​ 2019进入江西思诚科技有限公司担任云计算与数据库技术讲师，兼任OCP及RHCE认证讲师。</p><p>​ 2021年入职广东科技学院，担任软件工程专业专任教师。</p><p>​ 2025年合同到期，重新审视了自己的职业规划，寻找机会回归生产一线。</p><h2 id="我的-人生剧本" tabindex="-1">我的“人生剧本” <a class="header-anchor" href="#我的-人生剧本" aria-label="Permalink to &quot;我的“人生剧本”&quot;">​</a></h2><p>在此先说清楚三点：</p><p>1、八字命理只应是基于中华民间长期经验总结的概率型建议，类似“传统统计学 + 人文解释”，而不应是断言吉凶的宿命论。</p><p>2、要相信科学，不应迷信宿命论，命理学只应局限于性格与行为倾向、环境选择与风险点规避。</p><p>3、“人生剧本”只应是“参考模型”，不是行动替代品 八字≈一个传统的人生画像模型，用来校准方向，不是代替理性判断。</p><p>人生中有定数，也有变数，兼爱非攻，不忘初心，方可善始善终。</p><h3 id="四柱八字排盘" tabindex="-1">四柱八字排盘 <a class="header-anchor" href="#四柱八字排盘" aria-label="Permalink to &quot;四柱八字排盘&quot;">​</a></h3><p>四柱中日柱为：乙木（阴木）</p><h3 id="五行结构与强弱判断" tabindex="-1">五行结构与强弱判断 <a class="header-anchor" href="#五行结构与强弱判断" aria-label="Permalink to &quot;五行结构与强弱判断&quot;">​</a></h3><h4 id="五行分布" tabindex="-1">五行分布 <a class="header-anchor" href="#五行分布" aria-label="Permalink to &quot;五行分布&quot;">​</a></h4><ul><li><strong>木</strong>：有，但不旺</li><li><strong>火</strong>：<strong>明显偏旺</strong></li><li><strong>土</strong>：中等偏多</li><li><strong>金</strong>：有且位置关键</li><li><strong>水</strong>：极弱，几乎不显</li></ul><h4 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to &quot;一句话总结&quot;">​</a></h4><p>生于寒冬，水弱、火旺、土偏重，木偏弱</p><h3 id="从命理角度看底层性格逻辑" tabindex="-1">从命理角度看底层性格逻辑 <a class="header-anchor" href="#从命理角度看底层性格逻辑" aria-label="Permalink to &quot;从命理角度看底层性格逻辑&quot;">​</a></h3><h4 id="乙木的本质" tabindex="-1">乙木的本质 <a class="header-anchor" href="#乙木的本质" aria-label="Permalink to &quot;乙木的本质&quot;">​</a></h4><p>乙木不是参天大树，而是：</p><ul><li>藤蔓</li><li>花草</li><li>需要依附环境、借力生长</li></ul><p>👉 <strong>优势</strong>：</p><ul><li>适应性强</li><li>善于在规则中找空间</li><li>学习、模仿、优化能力强</li></ul><p>👉 <strong>弱点</strong>：</p><ul><li>容易被环境压制</li><li>如果资源（时间/情绪/精力）被持续消耗，会“枯萎”</li></ul><h4 id="火旺的影响-非常明显" tabindex="-1">火旺的影响（非常明显） <a class="header-anchor" href="#火旺的影响-非常明显" aria-label="Permalink to &quot;火旺的影响（非常明显）&quot;">​</a></h4><p>火旺克木，现实表现常见为：</p><ul><li>脑子转得快，想法多</li><li>表达欲、行动欲强</li><li>容易焦虑、内耗、熬夜、过度消耗自己</li></ul><blockquote><p>很多人会误以为这是“积极”“拼”，但对我来说，<strong>长期火旺是透支型</strong>。</p></blockquote><h4 id="水弱的真实含义" tabindex="-1">水弱的真实含义 <a class="header-anchor" href="#水弱的真实含义" aria-label="Permalink to &quot;水弱的真实含义&quot;">​</a></h4><p>水＝休息、缓冲、情绪修复、长期规划能力</p><p>命盘中水弱，意味着：</p><ul><li>不擅长“慢慢来”</li><li>很难真正放松</li><li>情绪容易靠“做事”来压，而不是被消化</li></ul><p>这也是中年阶段容易疲惫、怀疑自我的根源之一</p><h3 id="十神结构-→-行为模式判断" tabindex="-1">十神结构 → 行为模式判断 <a class="header-anchor" href="#十神结构-→-行为模式判断" aria-label="Permalink to &quot;十神结构 → 行为模式判断&quot;">​</a></h3><p>不讲命理学术语，直接给“人生剧本”的角色画像：</p><p>典型的“责任驱动 + 输出型人格”</p><ul><li>很难彻底躺平</li><li>哪怕失业、空窗，也会内心自责</li><li>容易把“价值感”绑定在： <blockquote><p>我今天有没有产出？有没有用？</p></blockquote></li></ul><p>⚠️ 风险：</p><ul><li>容易被“消耗型岗位 / 项目 / 人际关系”榨干</li><li>容易在不值得的地方坚持太久</li></ul><h3 id="结合以上的职业与现实路径规划" tabindex="-1">结合以上的职业与现实路径规划 <a class="header-anchor" href="#结合以上的职业与现实路径规划" aria-label="Permalink to &quot;结合以上的职业与现实路径规划&quot;">​</a></h3><h4 id="明确不利的方向" tabindex="-1">明确不利的方向 <a class="header-anchor" href="#明确不利的方向" aria-label="Permalink to &quot;明确不利的方向&quot;">​</a></h4><p>从命理 + 现实双重角度， <strong>长期不适合</strong>：</p><ul><li>高强度 996 / 持续救火岗位</li><li>永远“临时需求”“随时待命”的角色</li><li>纯人情、纯博弈、纯销售型工作</li></ul><p>这些都会 <strong>火土加重 → 木更弱</strong>。</p><h4 id="相对更优的方向" tabindex="-1">相对更优的方向 <a class="header-anchor" href="#相对更优的方向" aria-label="Permalink to &quot;相对更优的方向&quot;">​</a></h4><p>目前规划与人生剧本并不冲突，但要注意以下几点</p><h4 id="更适合自己的定位" tabindex="-1">更适合自己的定位 <a class="header-anchor" href="#更适合自己的定位" aria-label="Permalink to &quot;更适合自己的定位&quot;">​</a></h4><ul><li><strong>技术型支撑者</strong></li><li><strong>系统稳定性、规范、自动化</strong></li><li><strong>偏后端 / 偏底层 / 偏长期收益</strong></li></ul><p>包括但不限于：</p><ul><li>平台运维 / SRE（偏稳定性，而不是天天救火）</li><li>自动化、标准化、文档体系建设</li><li>一次投入，多次复用的工作</li></ul><p>👉 <strong>关键不是“技术 or 非技术”，而是：</strong></p><blockquote><p>能不能让自己的付出“沉淀下来”，而不是每天清零。</p></blockquote><h3 id="财务与人生节奏剧本" tabindex="-1">财务与人生节奏剧本 <a class="header-anchor" href="#财务与人生节奏剧本" aria-label="Permalink to &quot;财务与人生节奏剧本&quot;">​</a></h3><h4 id="快钱-风险极高" tabindex="-1">“快钱”风险极高 <a class="header-anchor" href="#快钱-风险极高" aria-label="Permalink to &quot;“快钱”风险极高&quot;">​</a></h4><p>命盘里：</p><ul><li>火旺 → 冲动</li><li>水弱 → 风控差</li><li>木弱 → 抗风险能力有限</li></ul><p>👉 非常不适合：</p><ul><li>高频投机</li><li>情绪化投资</li><li>押单一机会翻身</li></ul><h4 id="更适合的策略" tabindex="-1">更适合的策略 <a class="header-anchor" href="#更适合的策略" aria-label="Permalink to &quot;更适合的策略&quot;">​</a></h4><ul><li><strong>慢变量叠加</strong></li><li>多年技能积累</li><li>副业/项目以“复利”为目标</li></ul><p>哪怕慢，但不崩。</p><h3 id="中年剧本" tabindex="-1">中年剧本 <a class="header-anchor" href="#中年剧本" aria-label="Permalink to &quot;中年剧本&quot;">​</a></h3><blockquote><p><strong>不适合“硬扛”，适合“调结构”。</strong></p></blockquote><ul><li>明明很努力，但越走越累</li><li>越拼越怀疑自己</li><li>状态一年不如一年</li></ul><p>不是自己不行，而是：</p><blockquote><p><strong>环境五行不对。</strong></p></blockquote><p>换赛道、换节奏、换“付出—回报结构”， 比“再咬牙”要理性得多。</p><h3 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h3><blockquote><p><strong>我不是靠爆发翻盘的人，而是靠结构和耐力走远的人。</strong> 把自己放在“可持续的位置”，看不见的“人生剧本导演”自然会缓慢做出让步。</p></blockquote><h3 id="未来-10-年大运-流年趋势-2025–2035" tabindex="-1">未来 10 年大运 + 流年趋势（2025–2035） <a class="header-anchor" href="#未来-10-年大运-流年趋势-2025–2035" aria-label="Permalink to &quot;未来 10 年大运 + 流年趋势（2025–2035）&quot;">​</a></h3><blockquote><p>不下“哪年发财/倒霉”的断论，只讲<strong>结构变化与策略窗口</strong></p></blockquote><h4 id="大运背景" tabindex="-1">大运背景 <a class="header-anchor" href="#大运背景" aria-label="Permalink to &quot;大运背景&quot;">​</a></h4><p><strong>乙木日主，火土偏旺，水弱</strong></p><p>一生的关键逻辑是：</p><blockquote><p><strong>怕消耗，喜滋养；怕硬扛，喜结构优化</strong></p></blockquote><p>当前所处阶段，正从“责任压身期”过渡到“结构重建期”。</p><h4 id="_2025–2027-调整期-不要硬冲" tabindex="-1">2025–2027：调整期（不要硬冲） <a class="header-anchor" href="#_2025–2027-调整期-不要硬冲" aria-label="Permalink to &quot;2025–2027：调整期（不要硬冲）&quot;">​</a></h4><h5 id="命理结构" tabindex="-1">命理结构 <a class="header-anchor" href="#命理结构" aria-label="Permalink to &quot;命理结构&quot;">​</a></h5><ul><li>火土仍偏强</li><li>水未明显到位</li><li>来自外界的要求多、回报不稳定</li></ul><h5 id="现实表现-高概率" tabindex="-1">现实表现（高概率） <a class="header-anchor" href="#现实表现-高概率" aria-label="Permalink to &quot;现实表现（高概率）&quot;">​</a></h5><ul><li>学很多，但感觉“还不够”</li><li>容易怀疑方向是否选错</li><li>心态波动 &gt; 实际问题</li></ul><h5 id="策略规划" tabindex="-1"><strong>策略规划</strong> <a class="header-anchor" href="#策略规划" aria-label="Permalink to &quot;**策略规划**&quot;">​</a></h5><p>✅ 只做三件事：</p><ol><li><strong>补基础水位</strong>（休息、节律、持续学习）</li><li>不追风口、不盲转行</li><li>学“能复用 5 年以上”的东西</li></ol><p>❌ 绝对不做：</p><ul><li>再赌一次式转行</li><li>情绪化否定自己全部过去</li></ul><h4 id="_2028–2031-结构成型期-关键窗口" tabindex="-1">2028–2031：结构成型期（关键窗口） <a class="header-anchor" href="#_2028–2031-结构成型期-关键窗口" aria-label="Permalink to &quot;2028–2031：结构成型期（关键窗口）&quot;">​</a></h4><h5 id="命理变化" tabindex="-1">命理变化 <a class="header-anchor" href="#命理变化" aria-label="Permalink to &quot;命理变化&quot;">​</a></h5><ul><li>金、水开始显效（是好事）</li><li>外部规则、系统、平台开始趋于友好</li></ul><h5 id="现实表现" tabindex="-1">现实表现 <a class="header-anchor" href="#现实表现" aria-label="Permalink to &quot;现实表现&quot;">​</a></h5><ul><li>开始受到认可性评价：“稳！”</li><li>技术/经验不再是零散的</li><li>有机会进入 <strong>非救火型岗位</strong></li></ul><h5 id="策略" tabindex="-1"><strong>策略</strong> <a class="header-anchor" href="#策略" aria-label="Permalink to &quot;**策略**&quot;">​</a></h5><p>👉 这是 <strong>真正翻盘的窗口期</strong>，但不是靠拼命，而是：</p><ul><li>把会的东西“产品化 / 标准化”</li><li>开始从 <strong>执行者 转为 系统维护者</strong></li></ul><h4 id="_4️⃣-2032–2035-稳定回报期" tabindex="-1">4️⃣ 2032–2035：稳定回报期 <a class="header-anchor" href="#_4️⃣-2032–2035-稳定回报期" aria-label="Permalink to &quot;4️⃣ 2032–2035：稳定回报期&quot;">​</a></h4><h5 id="特点" tabindex="-1">特点 <a class="header-anchor" href="#特点" aria-label="Permalink to &quot;特点&quot;">​</a></h5><ul><li>收入不一定暴涨</li><li>心态明显稳</li><li>不再被轻易替代</li></ul><h5 id="最优状态" tabindex="-1">最优状态 <a class="header-anchor" href="#最优状态" aria-label="Permalink to &quot;最优状态&quot;">​</a></h5><blockquote><p>“我不抢机会，但机会会找到我”</p></blockquote><p>这是命盘里<strong>最舒服的一段人生节奏</strong>。</p><hr><h3 id="「最省力学习路径」" tabindex="-1">「最省力学习路径」 <a class="header-anchor" href="#「最省力学习路径」" aria-label="Permalink to &quot;「最省力学习路径」&quot;">​</a></h3><p>结合：</p><ul><li>乙木（怕消耗）</li><li>水弱（怕焦虑）</li></ul><p>👉 <strong>不适合“全栈焦虑型学习”</strong></p><h4 id="总原则" tabindex="-1">总原则 <a class="header-anchor" href="#总原则" aria-label="Permalink to &quot;总原则&quot;">​</a></h4><blockquote><p><strong>学“让系统自己跑”的东西，不学“靠人救火”的东西</strong></p></blockquote><h4 id="三层学习路径" tabindex="-1">三层学习路径 <a class="header-anchor" href="#三层学习路径" aria-label="Permalink to &quot;三层学习路径&quot;">​</a></h4><h5 id="🔹-第一层-稳态底座-必须扎实" tabindex="-1">🔹 第一层：稳态底座（必须扎实） <a class="header-anchor" href="#🔹-第一层-稳态底座-必须扎实" aria-label="Permalink to &quot;🔹 第一层：稳态底座（必须扎实）&quot;">​</a></h5><p>目标：<strong>降低焦虑</strong></p><ul><li>Linux 原理（不是命令堆）</li><li>TCP/IP、DNS、HTTP（慢慢啃）</li><li>Shell / Python（用于自动化，不求花哨）</li></ul><p>👉 这是在给你补“水”，不是浪费时间。</p><h5 id="🔹-第二层-云原生" tabindex="-1">🔹 第二层：云原生 <a class="header-anchor" href="#🔹-第二层-云原生" aria-label="Permalink to &quot;🔹 第二层：云原生&quot;">​</a></h5><p><strong>不适合</strong> 一上来就：</p><ul><li>深挖 CNI</li><li>魔改 kube-scheduler</li><li>跟大神卷源码</li></ul><p><strong>适合</strong>：</p><ul><li>Kubernetes 使用者视角</li><li>Helm / GitOps</li><li>CI/CD + 发布流程</li><li>可观测性（日志、指标、告警）</li></ul><p>👉 因为这些：</p><ul><li>一次学会，多年复用</li><li>不靠体力</li><li>不靠“随叫随到”</li></ul><h5 id="🔹-第三层-护城河-90-的人不愿做" tabindex="-1">🔹 第三层：护城河（90%的人不愿做） <a class="header-anchor" href="#🔹-第三层-护城河-90-的人不愿做" aria-label="Permalink to &quot;🔹 第三层：护城河（90%的人不愿做）&quot;">​</a></h5><p>这是翻身的关键：</p><ul><li>文档化能力</li><li>SOP / Runbook</li><li>系统化总结</li><li>把“经验”变成“流程”</li></ul><p><strong>乙木 + 金水起运的人，一定要靠这个赢。</strong></p><h4 id="学习节奏规划" tabindex="-1">学习节奏规划 <a class="header-anchor" href="#学习节奏规划" aria-label="Permalink to &quot;学习节奏规划&quot;">​</a></h4><p>❌ 不适合：</p><ul><li>每天 10 小时高强度猛学</li><li>逼自己打鸡血</li></ul><p>✅ 最优节奏：</p><ul><li>每天 2–4 小时</li><li>固定时间</li><li>长期不断</li></ul><blockquote><p>做耐力型，不做爆发型。</p></blockquote><h3 id="中年重建策略" tabindex="-1">中年重建策略 <a class="header-anchor" href="#中年重建策略" aria-label="Permalink to &quot;中年重建策略&quot;">​</a></h3><h4 id="中年低谷的真正原因-不是能力" tabindex="-1">中年低谷的真正原因（不是能力） <a class="header-anchor" href="#中年低谷的真正原因-不是能力" aria-label="Permalink to &quot;中年低谷的真正原因（不是能力）&quot;">​</a></h4><p>不是不够努力，而是：</p><ul><li>把 <strong>乙木</strong> 放进了 <strong>火土过旺的环境</strong></li><li>长期做“救火 / 顶雷 / 临时支撑”</li><li>回报结构严重不对等</li></ul><p>👉 <strong>这是结构问题，不是性格缺陷。</strong></p><h4 id="中年重建的三步规划-不要跳步" tabindex="-1">中年重建的三步规划（不要跳步） <a class="header-anchor" href="#中年重建的三步规划-不要跳步" aria-label="Permalink to &quot;中年重建的三步规划（不要跳步）&quot;">​</a></h4><h5 id="🔹-第一步-止损-心理-现实" tabindex="-1">🔹 第一步：止损（心理 + 现实） <a class="header-anchor" href="#🔹-第一步-止损-心理-现实" aria-label="Permalink to &quot;🔹 第一步：止损（心理 + 现实）&quot;">​</a></h5><ul><li>承认：这不是我该拼命的地方</li><li>不再用“再坚持一下”欺骗自己</li><li>接受：慢 ≠ 失败</li></ul><p>这是最难的一步。</p><h5 id="🔹-第二步-换结构-不换人格" tabindex="-1">🔹 第二步：换结构，不换人格 <a class="header-anchor" href="#🔹-第二步-换结构-不换人格" aria-label="Permalink to &quot;🔹 第二步：换结构，不换人格&quot;">​</a></h5><p>不需要：</p><ul><li>变外向</li><li>变狼性</li><li>变强势</li></ul><p>只需要：</p><ul><li>换岗位类型</li><li>换付出—回报模型</li><li>换节奏</li></ul><p>👉 <strong>人格是没问题的，环境是不合适的。</strong></p><h5 id="🔹-第三步-长期位-very-important" tabindex="-1">🔹 第三步：长期位（Very important） <a class="header-anchor" href="#🔹-第三步-长期位-very-important" aria-label="Permalink to &quot;🔹 第三步：长期位（Very important）&quot;">​</a></h5><p>最终应该站在：</p><ul><li>系统稳定性</li><li>平台支撑</li><li>规则维护</li><li>经验沉淀</li></ul><p>而不是：</p><ul><li>永远的一线救火员</li></ul><h4 id="重建核心结论" tabindex="-1">重建核心结论 <a class="header-anchor" href="#重建核心结论" aria-label="Permalink to &quot;重建核心结论&quot;">​</a></h4><blockquote><p><strong>人生不是“再拼一次”，而是“终于回归正轨”。</strong></p></blockquote>',179)])])}const b=l(r,[["render",t]]);export{c as __pageData,b as default};
